```js cms/schemas/forms/deskStructure.js
import S from '@sanity/desk-tool/structure-builder';
import { RiQuestionnaireLine, RiSurveyLine } from 'react-icons/ri';
import { marketList } from '../../lib/marketConfig';
import { FORM_QUESTION_TYPE } from './formQuestion';
import { POST_ACTIVATION_FORM_TYPE } from './postActivationForm';

function listPostActivationFormDocument(market) {
  return S.listItem()
    .title('Post Activation Form')
    .icon(RiSurveyLine)
    .child(
      S.document()
        .schemaType(POST_ACTIVATION_FORM_TYPE)
        .documentId(`${market.id}-${POST_ACTIVATION_FORM_TYPE}`),
    );
}

function listQuestionDocumentList(market) {
  return S.listItem()
    .title('Form Questions')
    .icon(RiQuestionnaireLine)
    .child(
      S.documentTypeList(FORM_QUESTION_TYPE)
        .title('Form Questions')
        .filter('_type == $type && references($marketId)')
        .params({
          type: FORM_QUESTION_TYPE,
          marketId: market.id,
        }),
    );
}

function listFormListsByMarket() {
  return S.list()
    .title('Forms')
    .items(
      marketList.map((market) => {
        return S.listItem()
          .title(`${market.name}`)
          .icon(() => market.icon)
          .child(
            S.list()
              .title(`${market.name}`)
              .items([
                listQuestionDocumentList(market),
                listPostActivationFormDocument(market),
              ]),
          );
      }),
    );
}

const formDocumentType = S.listItem().title('Forms').icon(RiSurveyLine);

export default formDocumentType.child(listFormListsByMarket());
```

