```js cms/schemas/forms/formOptions/index.js
import { displayedText, DISPLAYED_TEXT_TYPE } from '../displayedText';

import { getCloudFormOptionsWithValues } from '../../../lib/cloudApi';

// multiple choice
import { heardAboutUsMethod } from './heardAboutUsMethod';
import { interestingProduct } from './interestingProduct';
import { interestingPurchaseModel } from './interestingPurchaseModel';
import { preferredContactMethod } from './preferredContactMethod';
import { preferredContactTime } from './preferredContactTime';
import { specialCircumstances } from './specialCircumstances';

// radio
import { asbestosInRoof } from './asbestosInRoof';
import { consentToShareDataWithPartner } from './consentToShareDataWithPartner';
import { eaveHeight } from './eaveHeight';
import { gridPhase } from './gridPhase';
import { installationPlacement } from './installationPlacement';
import { intentionToBuy } from './intentionToBuy';
import { monthlyEnergyConsumption } from './monthlyEnergyConsumption';
import { monthlyEnergySpend } from './monthlyEnergySpend';
import { planningPermission } from './planningPermission';
import { preferredSubsidy } from './preferredSubsidy';
import { propertyOwnershipStatus } from './propertyOwnershipStatus';
import { roofSlope } from './roofSlope';
import { roofFrame } from './roofFrame';
import { standardElectricalCabinet } from './standardElectricalCabinet';
import { typeOfArea } from './typeOfArea';
import { yearlyEnergyConsumption } from './yearlyEnergyConsumption';
import { yearlyEnergySpend } from './yearlyEnergySpend';

// Numeric fields
import { monthlyEnergyBill } from './monthlyEnergyBill';
import { yearlyConsumptionKWh } from './yearlyConsumptionKWh';

// special fields
import { fileUpload } from './fileUpload';
import { mountingSurface } from './mountingSurface';

const allFormOptions = {
  // multiple choice
  heardAboutUsMethod,
  interestingProduct,
  preferredContactMethod,
  preferredContactTime,
  interestingPurchaseModel,
  specialCircumstances,
  // radio
  asbestosInRoof,
  consentToShareDataWithPartner,
  gridPhase,
  intentionToBuy,
  propertyOwnershipStatus,
  monthlyEnergySpend,
  monthlyEnergyConsumption,
  preferredSubsidy,
  yearlyEnergySpend,
  yearlyEnergyConsumption,
  typeOfArea,
  planningPermission,
  installationPlacement,
  roofSlope,
  roofFrame,
  standardElectricalCabinet,
  eaveHeight,
  // Numeric
  yearlyConsumptionKWh,
  monthlyEnergyBill,
  // special fields
  fileUpload,
  mountingSurface,
};

getCloudFormOptionsWithValues().then((cloudFormOptions) => {
  const populateOptionsFromCloud = (formOptions) => {
    const field = formOptions.fields.find((x) => x.name === 'formOption');
    field.options.list = cloudFormOptions[formOptions.name].map(
      /* eslint-disable camelcase */
      ({ displayed_text: title, value }) => {
        return {
          value,
          title,
        };
      },
    );
  };

  Object.values(allFormOptions).forEach(populateOptionsFromCloud);
});

export default Object.values(allFormOptions).map((option) => {
  return {
    ...option,
    fields: [...option.fields, displayedText],
    preview: {
      select: {
        title: DISPLAYED_TEXT_TYPE,
        subtitle: option.fields[0].name,
      },
      prepare({ title, subtitle }) {
        return {
          title,
          subtitle,
        };
      },
    },
  };
});
