```js cms/schemas/forms/formQuestion.js
import { RiQuestionnaireLine } from 'react-icons/ri';

import { splitCamelCase, titleCase } from '../../lib/stringUtils';
import { allMarkets } from '../marketReference';

import { EXAMPLE_PHOTOS } from './examplePhotos';
import formOptions from './formOptions/index';

export const FORM_QUESTION_TYPE = 'formQuestion';

export default {
  name: FORM_QUESTION_TYPE,
  title: FORM_QUESTION_TYPE,
  i18n: true,
  initialValue: {
    __i18n_lang: '',
  },
  type: 'document',
  icon: RiQuestionnaireLine,
  fields: [
    {
      ...allMarkets,
      validation: (Rule) => Rule.required(),
    },
    {
      title: 'Heading',
      name: 'formQuestionText',
      type: 'text',
      validation: (Rule) => Rule.required(),
      hidden: ({ document }) => {
        return !document?.market?._ref;
      },
    },
    {
      title: 'Description',
      name: 'formQuestionDescription',
      type: 'text',
      hidden: ({ document }) => {
        return !document?.market?._ref;
      },
      description:
        'You can use this field to provide extra information to the customer.',
    },
    {
      title: 'Question',
      name: 'formInputName',
      type: 'string',
      options: {
        list: formOptions.map((option) => ({
          value: option.name,
          title: option.title,
        })),
      },
      validation: (Rule) => Rule.required(),
    },
    ...formOptions.map((option) => {
      return {
        title: option.title,
        name: option.name,
        type: 'array',
        of: [
          {
            type: option.name,
          },
        ],
        hidden: ({ parent }) => {
          return parent?.formInputName !== option.name;
        },
      };
    }),
    {
      name: EXAMPLE_PHOTOS,
      type: EXAMPLE_PHOTOS,
      options: { collapsible: true },
    },
  ],
  preview: {
    select: {
      formQuestionText: 'formQuestionText',
      formInputName: 'formInputName',
    },
    prepare({ formQuestionText, formInputName }) {
      const title = formInputName
        ? titleCase(splitCamelCase(formInputName))
        : 'Missing Question';
      return {
        title: `${title} - ${formQuestionText}`,
      };
    },
  },
};
