// Assuming you've run the GROQ query and have the results stored in `documents`
function analyzeDuplicates(documents) {
  const listFormatter = new Intl.ListFormat('en', { 
    style: 'long',
    type: 'conjunction'
  });

  // Group by market for organized reporting
  const marketProblems = {};

  documents.forEach(doc => {
    if (!doc.values) return;

    // Find duplicates in values array
    const valueCount = {};
    const duplicates = [];

    doc.values.forEach(value => {
      valueCount[value] = (valueCount[value] || 0) + 1;
      if (valueCount[value] === 2) {
        duplicates.push(value);
      }
    });

    // If duplicates found, add to market problems
    if (duplicates.length > 0) {
      if (!marketProblems[doc.market]) {
        marketProblems[doc.market] = [];
      }

      marketProblems[doc.market].push({
        formInputName: doc.formInputName,
        duplicateValues: duplicates,
        allValues: doc.values,
        documentId: doc._id
      });
    }
  });

  // Print results
  if (Object.keys(marketProblems).length === 0) {
    console.log('✅ No duplicate values found in any market');
    return;
  }

  console.log('🚨 Found duplicate values in the following markets:\n');

  Object.entries(marketProblems).forEach(([market, problems]) => {
